   106→// Candidate views offer (track engagement)
   107→router.post('/offers/:id/view', authMiddleware, async (req, res) => {
   108→  try {
   109→    const result = await pool.query(
   110→      `UPDATE offers
   111→       SET viewed_at = NOW(), updated_at = NOW()
   112→       WHERE id = $1 AND candidate_id = $2
   113→       RETURNING *`,
