   275→// Update checklist item completion
   276→router.post('/checklists/:id/complete', authMiddleware, async (req, res) => {
   277→  try {
   278→    const { item_id } = req.body;
   279→
   280→    const checklist = await pool.query(
   281→      'SELECT * FROM onboarding_checklists WHERE id = $1 AND candidate_id = $2',
   282→      [req.params.id, req.user.id]
   283→    );
   284→
   285→    if (checklist.rows.length === 0) {
   286→      return res.status(404).json({ error: 'Checklist not found' });
   287→    }
   288→
   289→    const completedItems = checklist.rows[0].completed_items || [];
   290→    if (!completedItems.includes(item_id)) {
   291→      completedItems.push(item_id);
   292→    }
   293→
   294→    const items = checklist.rows[0].items || [];
   295→    const allCompleted = items.every(item => completedItems.includes(item.id));
   296→
   297→    const result = await pool.query(
   298→      `UPDATE onboarding_checklists
   299→       SET completed_items = $1,
   300→           status = $2,
   301→           completed_at = $3,
   302→           updated_at = NOW()
   303→       WHERE id = $4
   304→       RETURNING *`,
   305→      [
   306→        JSON.stringify(completedItems),
   307→        allCompleted ? 'completed' : 'in_progress',
   308→        allCompleted ? new Date() : null,
   309→        req.params.id
   310→      ]
   311→    );
   312→
   313→    res.json(result.rows[0]);
   314→  } catch (err) {
   315→    console.error('Error updating checklist:', err);
   316→    res.status(500).json({ error: 'Failed to update checklist' });
   317→  }
   318→});
