   384→        'What has exceeded your expectations?'
   385→      ]
   386→    };
   387→
   388→    const result = await pool.query(
   389→      `INSERT INTO post_hire_feedback
   390→       (employee_id, manager_id, feedback_type, day_mark, questions, status, sent_at)
   391→       VALUES ($1, $2, $3, $4, $5, $6, NOW())
   392→       RETURNING *`,
   393→      [
   394→        employee_id,
   395→        req.user.id,
   396→        'check_in',
   397→        day_mark,
   398→        JSON.stringify(questions[day_mark] || questions[30]),
   399→        'sent'
   400→      ]
   401→    );
   402→
   403→    res.json(result.rows[0]);
   404→  } catch (err) {
   405→    console.error('Error scheduling feedback:', err);
   406→    res.status(500).json({ error: 'Failed to schedule feedback' });
   407→  }
