   431→
   432→    // Analyze feedback with AI
   433→    const aiAnalysis = await analyzeFeedbackWithAI(responses, comments);
   434→
   435→    const result = await pool.query(
   436→      `UPDATE post_hire_feedback
   437→       SET responses = $1,
