   442→           status = 'completed',
   443→           completed_at = NOW()
   444→       WHERE id = $6 AND employee_id = $7
   445→       RETURNING *`,
   446→      [
   447→        JSON.stringify(responses),
   448→        satisfaction_score,
   449→        would_recommend,
