   467→
   468→// Get feedback analytics for manager
   469→router.get('/feedback/analytics', authMiddleware, async (req, res) => {
   470→  try {
   471→    const result = await pool.query(
   472→      `SELECT
   473→        day_mark,
   474→        AVG(satisfaction_score) as avg_satisfaction,
   475→        COUNT(*) as total_responses,
   476→        SUM(CASE WHEN would_recommend THEN 1 ELSE 0 END) as would_recommend_count
   477→      FROM post_hire_feedback
   478→      WHERE manager_id = $1 AND status = 'completed'
