   491→// ============================================
   492→// ONBOARDING AI ASSISTANT
   493→// ============================================
   494→
   495→// Start or continue chat session
   496→router.post('/assistant/chat', authMiddleware, async (req, res) => {
   497→  try {
   498→    const { message, checklist_id } = req.body;
   499→
   500→    // Get or create chat session
   501→    let session = await pool.query(
   502→      `SELECT * FROM onboarding_chats
   503→       WHERE candidate_id = $1 AND checklist_id = $2 AND is_active = true
   504→       ORDER BY session_started DESC LIMIT 1`,
   505→      [req.user.id, checklist_id || null]
   506→    );
   507→
   508→    let sessionId;
   509→    let messages = [];
   510→
   511→    if (session.rows.length === 0) {
   512→      const newSession = await pool.query(
   513→        `INSERT INTO onboarding_chats (candidate_id, checklist_id, messages)
   514→         VALUES ($1, $2, $3)
   515→         RETURNING *`,
   516→        [req.user.id, checklist_id || null, JSON.stringify([])]
   517→      );
   518→      sessionId = newSession.rows[0].id;
   519→    } else {
   520→      sessionId = session.rows[0].id;
   521→      messages = session.rows[0].messages || [];
   522→    }
   523→
   524→    // Get company policies for context
   525→    const policies = await pool.query(
   526→      `SELECT category, title, content
   527→       FROM company_policies
   528→       WHERE is_active = true
   529→       ORDER BY category`
   530→    );
   531→
   532→    // Build context from policies
   533→    const policyContext = policies.rows.map(p =>
   534→      `${p.category}: ${p.title}\n${p.content}`
   535→    ).join('\n\n');
   536→
   537→    // Add user message
   538→    messages.push({
   539→      role: 'user',
   540→      content: message,
   541→      timestamp: new Date().toISOString()
   542→    });
   543→
   544→    // Get AI response
   545→    const aiResponse = await getOnboardingAssistantResponse(
   546→      messages,
   547→      policyContext,
   548→      req.user
   549→    );
   550→
   551→    // Add AI response
   552→    messages.push({
   553→      role: 'assistant',
   554→      content: aiResponse,
   555→      timestamp: new Date().toISOString()
   556→    });
   557→
   558→    // Update session
   559→    await pool.query(
   560→      `UPDATE onboarding_chats
   561→       SET messages = $1, last_activity = NOW()
   562→       WHERE id = $2`,
   563→      [JSON.stringify(messages), sessionId]
   564→    );
   565→
   566→    res.json({ response: aiResponse, session_id: sessionId });
   567→  } catch (err) {
   568→    console.error('Error in assistant chat:', err);
   569→    res.status(500).json({ error: 'Failed to process chat message' });
   570→  }
   571→});
   572→
   573→// Get chat history
   574→router.get('/assistant/history/:session_id', authMiddleware, async (req, res) => {
   575→  try {
   576→    const result = await pool.query(
   577→      `SELECT * FROM onboarding_chats
   578→       WHERE id = $1 AND candidate_id = $2`,
   579→      [req.params.session_id, req.user.id]
   580→    );
   581→
   582→    if (result.rows.length === 0) {
   583→      return res.status(404).json({ error: 'Session not found' });
   584→    }
   585→
   586→    res.json(result.rows[0]);
   587→  } catch (err) {
   588→    console.error('Error fetching chat history:', err);
   589→    res.status(500).json({ error: 'Failed to fetch chat history' });
   590→  }
