   675→// Get onboarding summary for recruiter dashboard (candidates with pending docs)
   676→router.get('/recruiter/summary', authMiddleware, async (req, res) => {
   677→  try {
   678→    // Verify user is a recruiter
   679→    if (!req.user.company_id) {
   680→      return res.status(403).json({ error: 'Only recruiters can view onboarding documents' });
   681→    }
   682→
   683→    const result = await pool.query(
   684→      `SELECT
   685→        u.id as candidate_id,
   686→        u.name as candidate_name,
   687→        u.email as candidate_email,
   688→        COUNT(od.id) as total_documents,
   689→        SUM(CASE WHEN od.status = 'completed' OR od.signed_at IS NOT NULL THEN 1 ELSE 0 END) as signed_documents,
   690→        MAX(od.created_at) as last_activity,
   691→        oc.status as checklist_status,
   692→        oc.due_date,
   693→        j.title as job_title,
   694→        cod.wizard_status,
   695→        cod.current_step as wizard_step
   696→      FROM users u
   697→      JOIN offers o ON u.id = o.candidate_id
   698→      LEFT JOIN onboarding_checklists oc ON u.id = oc.candidate_id
   699→      LEFT JOIN onboarding_documents od ON u.id = od.candidate_id
   700→      LEFT JOIN jobs j ON o.job_id = j.id
   701→      LEFT JOIN candidate_onboarding_data cod ON u.id = cod.candidate_id AND cod.checklist_id = oc.id
   702→      WHERE o.company_id = $1 AND o.status IN ('accepted', 'completed')
   703→      GROUP BY u.id, u.name, u.email, oc.status, oc.due_date, j.title, cod.wizard_status, cod.current_step
   704→      ORDER BY u.created_at DESC`,
   705→      [req.user.company_id]
   706→    );
   707→
   708→    // Derive real status from actual document progress (not checklist which may be fake-completed)
   709→    const candidates = result.rows.map(r => {
   710→      const totalDocs = parseInt(r.total_documents) || 0;
   711→      const signedDocs = parseInt(r.signed_documents) || 0;
   712→      let onboarding_status;
   713→
   714→      if (r.wizard_status === 'completed' && totalDocs > 0 && signedDocs === totalDocs) {
