   747→// Get wizard progress for current candidate
   748→router.get('/wizard/progress', authMiddleware, async (req, res) => {
   749→  try {
   750→    // Get candidate's active checklist
   751→    const checklist = await pool.query(
   752→      `SELECT oc.*, o.title as offer_title, o.company_name, o.salary, o.start_date,
   753→              j.title as job_title
   754→       FROM onboarding_checklists oc
   755→       JOIN offers o ON oc.offer_id = o.id
