   760→    );
   761→
   762→    if (checklist.rows.length === 0) {
   763→      return res.json({ has_onboarding: false });
   764→    }
   765→
   766→    const cl = checklist.rows[0];
   767→
   768→    // Get or create wizard data
   769→    let wizardData = await pool.query(
   770→      'SELECT * FROM candidate_onboarding_data WHERE candidate_id = $1 AND checklist_id = $2',
   771→      [req.user.id, cl.id]
   772→    );
   773→
   774→    if (wizardData.rows.length === 0) {
   775→      // First time visiting the real wizard — create fresh wizard data
   776→      wizardData = await pool.query(
   777→        `INSERT INTO candidate_onboarding_data (candidate_id, checklist_id)
   778→         VALUES ($1, $2)
   779→         RETURNING *`,
   780→        [req.user.id, cl.id]
   781→      );
   782→
   783→      // If the old fake auto-complete system marked the checklist as "completed"
   784→      // but no real wizard data exists, reset the checklist so the candidate
   785→      // can go through the real flow
   786→      if (cl.status === 'completed' || cl.status === 'in_progress') {
   787→        const existingDocs = await pool.query(
