   791→        if (parseInt(existingDocs.rows[0].cnt) === 0) {
   792→          // No real documents = the old system faked it. Reset.
   793→          await pool.query(
   794→            `UPDATE onboarding_checklists SET
   795→              status = 'in_progress',
   796→              completed_items = '[]'::jsonb,
   797→              completed_at = NULL,
   798→              updated_at = NOW()
   799→             WHERE id = $1`,
   800→            [cl.id]
   801→          );
   802→          cl.status = 'in_progress';
   803→          cl.completed_items = [];
   804→        }
   805→      }
   806→    }
   807→
   808→    // Get existing documents
   809→    const documents = await pool.query(
   810→      'SELECT * FROM onboarding_documents WHERE candidate_id = $1 AND checklist_id = $2 ORDER BY created_at',
   811→      [req.user.id, cl.id]
   812→    );
   813→
   814→    res.json({
   815→      has_onboarding: true,
   816→      checklist: cl,
   817→      wizard: wizardData.rows[0],
   818→      documents: documents.rows
   819→    });
   820→  } catch (err) {
   821→    console.error('Error getting wizard progress:', err);
   822→    res.status(500).json({ error: 'Failed to get wizard progress' });
   823→  }
   824→});
